#!/usr/bin/env python3
"""
ws_daemon — 独立 WebSocket 进程（话题模式）
- WS 收到消息 → 发布 ROS2 话题 `aipet/ws/relay_delivery`
- 订阅 `aipet/ws/relay_result` → WS 上报服务器
"""
import sys
import os
sys.path.insert(0, os.path.dirname(__file__))

import json
import threading
import time
import logging
from datetime import datetime

try:
    import websocket
except ImportError:
    websocket = None

import urllib.request

logging.basicConfig(
    level=logging.INFO,
    format='[%(asctime)s] [%(levelname)s] %(message)s',
    datefmt='%H:%M:%S',
)
log = logging.getLogger('wsd')


class WSMiddlewareAdapter:
    def __init__(self):
        cfg = {'enabled': True, 'person_found': True, 'wait_seconds': 10, 'max_retries': 3}
        self.simulation = {
            'enabled': cfg.get('enabled', True),
            'person_found': cfg.get('person_found', True),
            'wait_seconds': cfg.get('wait_seconds', 10),
            'max_retries': cfg.get('max_retries', 3),
        }
        self._simulation_lock = threading.Lock()
        self._found_event = threading.Event()

    def get_logger(self):
        return log


class WSClient:
    def __init__(self, ws_url, token, adapter):
        self.ws_url = ws_url
        self.token = token
        self.adapter = adapter
        self.ws = None
        self.connected = threading.Event()
        self._stop = threading.Event()
        self._found_event = adapter._found_event
        self.running = True
        self._ros_pub = None  # 由 main() 注入 ROS2 发布函数

    def connect(self):
        if websocket is None:
            log.error('websocket-client 未安装')
            return
        def _run():
            backoff = 1
            max_backoff = 60
            while not self._stop.is_set():
                try:
                    self.ws = websocket.WebSocketApp(
                        self.ws_url,
                        on_open=self._on_open,
                        on_message=self._on_message,
                        on_error=self._on_error,
                        on_close=self._on_close,
                    )
                    self.ws.run_forever(ping_interval=25, ping_timeout=10)
                except Exception as e:
                    log.error(f'WS 异常: {e}')
                if not self._stop.is_set():
                    log.info(f'WS 将在 {backoff} 秒后重连...')
                    self._backoff_sleep(backoff)
                    backoff = min(backoff * 2, max_backoff)
        self._thread = threading.Thread(target=_run, daemon=True)
        self._thread.start()

    def _backoff_sleep(self, sec):
        for _ in range(int(sec * 10)):
            if self._stop.is_set():
                return
            time.sleep(0.1)

    def _on_open(self, ws):
        log.info('WS 已连接，发送认证...')
        ws.send(json.dumps({'type': 'auth', 'access_token': self.token}))

    def _on_message(self, ws, message):
        try:
            data = json.loads(message)
            msg_type = data.get('type', '')
            if msg_type == 'auth':
                if data.get('success'):
                    self.connected.set()
                    log.info('✅ 认证成功')
                    self.ws.send(json.dumps({'type': 'config_request'}))
                else:
                    log.error(f'❌ 认证失败: {data.get("message","")}')

            elif msg_type == 'heartbeat':
                pass

            elif msg_type == 'relay_message_delivery':
                # 发布到 ROS2 话题，relay_node 订阅后会写入 tasks/
                if self._ros_pub:
                    self._ros_pub(json.dumps(data, ensure_ascii=False))
                rid = data.get('relay_id', '') or data.get('relayId', '') or ''
                log.info(f'📨 收到传话: {rid[:40]}')

            elif msg_type == 'server_command':
                params = data.get('command_params') or data.get('params') or {}
                sim_updates = {}
                for k in ('person_found', 'wait_seconds', 'enabled', 'max_retries'):
                    if k in params:
                        v = params[k]
                        if k == 'wait_seconds':
                            sim_updates[k] = int(v)
                        elif k == 'max_retries':
                            sim_updates[k] = int(v)
                        else:
                            sim_updates[k] = bool(v)
                if sim_updates:
                    with self.adapter._simulation_lock:
                        self.adapter.simulation.update(sim_updates)
                    for k, v in sim_updates.items():
                        log.info(f'🎮 模拟更新: {self.adapter.simulation}')
                    if hasattr(self, '_ros_sim_pub') and self._ros_sim_pub:
                        self._ros_sim_pub(json.dumps(self.adapter.simulation))
                if self._ros_pub:
                    self._ros_pub(json.dumps({
                        'type': 'server_command', 'data': data,
                    }, ensure_ascii=False))
                ws.send(json.dumps({
                    'type': 'command_response',
                    'command_id': data.get('command_id', ''),
                    'command': data.get('command') or data.get('command_type', ''),
                    'status': 'success',
                    'result': {'received': True},
                }))

            elif msg_type == 'chat':
                content = data.get('content', '')
                if content.startswith('/sim '):
                    try:
                        cmd = json.loads(content[5:])
                        updates = {}
                        for k in ('person_found', 'wait_seconds', 'enabled', 'max_retries'):
                            if k in cmd:
                                v = cmd[k]
                                if k == 'wait_seconds':
                                    updates[k] = int(v)
                                elif k == 'max_retries':
                                    updates[k] = int(v)
                                else:
                                    updates[k] = bool(v)
                        if updates:
                            with self.adapter._simulation_lock:
                                self.adapter.simulation.update(updates)
                            log.info(f'🎮 模拟更新: {self.adapter.simulation}')
                            if hasattr(self, '_ros_sim_pub') and self._ros_sim_pub:
                                self._ros_sim_pub(json.dumps(self.adapter.simulation))
                        return
                    except json.JSONDecodeError:
                        log.warn(f'sim 格式错: {content}')
                        return
                if self._ros_pub:
                    self._ros_pub(json.dumps({'type': 'chat', 'data': data}, ensure_ascii=False))

            elif msg_type == 'config_response':
                if self._ros_pub:
                    self._ros_pub(json.dumps({'type': 'config_response', 'data': data}, ensure_ascii=False))

        except json.JSONDecodeError:
            log.error(f'JSON 解析失败: {message}')
        except Exception as e:
            log.error(f'消息处理异常: {e}')

    def _on_error(self, ws, error):
        self.connected.clear()
        log.error(f'WS 错误: {error}')

    def _on_close(self, ws, code, msg):
        self.connected.clear()
        log.info(f'WS 关闭: code={code}')

    def stop(self):
        self._stop.set()
        self.running = False
        if self.ws:
            self.ws.close()


# ─── 上报循环 ────────────────────────────────────────

# ─── ROS2 桥接线程 ────────────────────────────────

def start_ros_bridge(ws_send_fn):
    """启动 ROS2 桥接线程，返回 {'publish': fn, 'publish_sim': fn}"""
    import rclpy
    from std_msgs.msg import String
    import queue

    q = queue.Queue()
    q_sim = queue.Queue()
    _ros_pub = None
    _sim_pub = None

    def _run():
        nonlocal _ros_pub, _sim_pub
        rclpy.init()
        node = rclpy.create_node('ws_daemon_bridge')
        _ros_pub = node.create_publisher(String, 'aipet/ws/relay_delivery', 10)
        _sim_pub = node.create_publisher(String, 'aipet/bt/sim_config', 10)
        node.create_subscription(String, 'aipet/ws/relay_result',
                                 lambda msg: (log.info(f'📥 WS结果: {msg.data[:60]}'), ws_send_fn(msg.data))[1], 10)
        while rclpy.ok():
            try:
                payload = q.get(timeout=0.1)
                if payload and _ros_pub:
                    m = String(); m.data = payload
                    _ros_pub.publish(m)
            except queue.Empty:
                pass
            try:
                payload = q_sim.get_nowait()
                if payload and _sim_pub:
                    m = String(); m.data = payload
                    _sim_pub.publish(m)
            except queue.Empty:
                pass
            rclpy.spin_once(node, timeout_sec=0.05)
        rclpy.shutdown()

    import threading as _thr
    _thr.Thread(target=_run, daemon=True).start()
    time.sleep(0.5)

    def publish(payload):
        q.put(payload)

    def publish_sim(payload):
        q_sim.put(payload)

    return {'publish': publish, 'publish_sim': publish_sim}


def main():
    # 单实例保护：PID 锁文件
    _PID_FILE = '/tmp/ws_daemon.pid'
    try:
        if os.path.exists(_PID_FILE):
            with open(_PID_FILE) as f:
                old_pid = int(f.read().strip())
            if old_pid > 0:
                try:
                    os.kill(old_pid, 15)
                    time.sleep(0.3)
                    os.kill(old_pid, 9)
                except (OSError, ProcessLookupError):
                    pass
        with open(_PID_FILE, 'w') as f:
            f.write(str(os.getpid()))
    except Exception:
        pass

    host = sys.argv[1] if len(sys.argv) > 1 else '47.118.26.156'
    port = int(sys.argv[2]) if len(sys.argv) > 2 else 8000
    sn = sys.argv[3] if len(sys.argv) > 3 else '6976f96f-bc80-56e3-9b27-13d12cdde9d1'

    log.info(f'🚀 WS Daemon 启动（话题模式）: {host}:{port} sn={sn}')

    # 获取 WS 令牌
    url = f'http://{host}:{port}/api/v1/aipet/ws/auth/{sn}'
    try:
        req = urllib.request.urlopen(url, timeout=10)
        token = json.loads(req.read()).get('data')
        if not token:
            log.error('❌ 获取 token 失败')
            return
    except Exception as e:
        log.error(f'❌ token 异常: {e}')
        return

    adapter = WSMiddlewareAdapter()
    ws_url = f'ws://{host}:{port}/api/v1/aipet/ws/{sn}'
    client = WSClient(ws_url, token, adapter)
    client.connect()
    time.sleep(1)

    # ROS2 桥接线程
    def ws_send_wrapper(data):
        if client and client.ws and client.connected.is_set():
            try:
                client.ws.send(data)
            except Exception as e:
                log.error(f'WS send 失败: {e}')
    bridge = start_ros_bridge(ws_send_wrapper)
    client._ros_pub = bridge['publish']
    client._ros_sim_pub = bridge['publish_sim']
    ros_sim_pub = bridge['publish_sim']

    log.info('✅ 全部就绪')
    # 启动简易 HTTP 服务（供 bt_monitor.html 获取 bt_status.json）
    try:
        import http.server
        import socketserver
        class Handler(http.server.SimpleHTTPRequestHandler):
            def do_GET(self):
                if self.path == '/bt_status.json' or self.path.startswith('/bt_status.json?'):
                    self.send_response(200)
                    self.send_header('Content-Type', 'application/json')
                    self.send_header('Access-Control-Allow-Origin', '*')
                    self.end_headers()
                    try:
                        with open(os.path.expanduser('~/bt_status.json'), 'rb') as f:
                            self.wfile.write(f.read())
                    except FileNotFoundError:
                        self.wfile.write(b'{}')
                else:
                    self.send_response(404)
                    self.end_headers()
        httpd = socketserver.ThreadingTCPServer(('', 8767), Handler)
        threading.Thread(target=httpd.serve_forever, daemon=True).start()
        log.info('📊 BT 状态 HTTP 服务: http://0.0.0.0:8767/bt_status.json')
    except Exception as e:
        log.warn(f'HTTP 服务启动失败: {e}')
    try:
        while not client._stop.is_set():
            time.sleep(1)
    except KeyboardInterrupt:
        client.stop()


if __name__ == '__main__':
    main()
